(function ($) {
    'use strict';

    if (window._tableSortInit) return;
    window._tableSortInit = true;

    $(function () {
        // --- Sortable headers ---
        $('th[data-sort-type]').each(function () {
            var $th = $(this);
            if ($th.data('sort-type') === 'none') return;
            $th.addClass('sortable');
        });

        $('th.sortable').on('click', function (e) {
            // Ignore clicks on filter inputs/selects
            if ($(e.target).hasClass('col-filter')) return;

            var $th   = $(this);
            var table = $th.closest('table')[0];
            var tbody = table.tBodies[0];
            if (!tbody) return;

            var colIdx = $th.index();
            var type   = $th.data('sort-type') || 'text';
            var asc    = !$th.hasClass('sort-asc');

            // Reset siblings
            $th.closest('tr').find('th').removeClass('sort-asc sort-desc');
            $th.addClass(asc ? 'sort-asc' : 'sort-desc');

            var rows = Array.prototype.slice.call(tbody.rows);

            rows.sort(function (a, b) {
                var cellA = a.cells[colIdx];
                var cellB = b.cells[colIdx];
                var valA  = (cellA ? cellA.textContent : '').trim();
                var valB  = (cellB ? cellB.textContent : '').trim();

                var cmp = compare(valA, valB, type);
                return asc ? cmp : -cmp;
            });

            for (var i = 0; i < rows.length; i++) {
                tbody.appendChild(rows[i]);
            }
        });

        // --- Per-column filter inputs ---
        $('table').has('th.sortable').each(function () {
            var $table = $(this);
            var $thead = $table.find('thead');
            var $headerRow = $thead.find('tr').first();
            var $filterRow = $('<tr class="filter-row no-print"></tr>');

            $headerRow.find('th').each(function (thIdx) {
                var $th = $(this);
                var sortType = $th.data('sort-type');
                var filterType = $th.data('filter-type');
                var $td = $('<td></td>');

                // Copy responsive-pass-* and *-col classes from th to filter td
                var thClasses = ($th.attr('class') || '').split(/\s+/);
                for (var ci = 0; ci < thClasses.length; ci++) {
                    if (thClasses[ci].indexOf('responsive-pass-') === 0 || thClasses[ci].match(/-col$/)) {
                        $td.addClass(thClasses[ci]);
                    }
                }

                // Match visibility: if th was hidden by another script, hide filter td too
                if ($th.is(':hidden')) {
                    $td.hide();
                }

                if (sortType && sortType !== 'none') {
                    if (filterType === 'select' || filterType === 'budget') {
                        // Collect unique values from column cells
                        var values = [];
                        var seen = {};
                        $table.find('tbody tr').each(function () {
                            var cell = this.cells[thIdx];
                            var text = (cell ? cell.textContent : '').trim();
                            if (text && text !== '-' && !seen[text]) {
                                seen[text] = true;
                                values.push(text);
                            }
                        });
                        values.sort(function (a, b) {
                            return a.localeCompare(b, 'de', { sensitivity: 'base' });
                        });

                        var $select = $('<select class="col-filter form-select form-select-sm"></select>');
                        $select.append('<option value="">Alle</option>');
                        if (filterType === 'budget') {
                            $select.append('<option value="__has_budget__">Mit Budget</option>');
                        }
                        for (var i = 0; i < values.length; i++) {
                            $select.append($('<option></option>').val(values[i]).text(values[i]));
                        }
                        $select.on('change', function () {
                            applyFilters($table);
                        });
                        $td.append($select);
                    } else {
                        var isNrCol = $th.hasClass('nr-col');
                        var placeholder = isNrCol ? 'Nr...' : 'Filter...';
                        var $input = $('<input type="text" class="col-filter form-control form-control-sm" placeholder="' + placeholder + '">');
                        if (isNrCol) {
                            function bidSearchRedirect(val) {
                                var url = new URL(window.location.href);
                                url.searchParams.set('search', '(bid = ' + val + ')');
                                url.searchParams.set('all-dates', '1');
                                url.searchParams.delete('page');
                                window.location.href = url.toString();
                            }
                            $input.on('keydown', function (e) {
                                if (e.key === 'Enter') {
                                    e.preventDefault();
                                    var val = $(this).val().trim();
                                    if (val && /^\d+$/.test(val)) {
                                        bidSearchRedirect(val);
                                    }
                                }
                            });
                            var $nrInput = $input;
                            var $nrTd = $td;
                            $input.on('input', function () {
                                var val = $nrInput.val().trim();
                                $nrTd.find('.nr-search-hint').remove();
                                if (val && /^\d+$/.test(val)) {
                                    var visibleRows = $table.find('tbody tr:visible').length;
                                    if (visibleRows === 0) {
                                        var $hint = $('<a href="#" class="nr-search-hint" style="font-size:0.7rem;display:block;margin-top:2px;">Suchen ↵</a>');
                                        $hint.on('click', function (e) {
                                            e.preventDefault();
                                            bidSearchRedirect(val);
                                        });
                                        $nrTd.append($hint);
                                    }
                                }
                            });
                        }
                        $input.on('keydown', function (e) {
                            if (e.key === 'Enter' && !isNrCol) {
                                e.preventDefault();
                                var val = $(this).val().trim();
                                if (val && val.length >= 2) {
                                    var visibleRows = $table.find('tbody tr:visible').length;
                                    var totalRows = $table.find('tbody tr').length;
                                    if (visibleRows === 0 || visibleRows < totalRows) {
                                        var url = new URL(window.location.href);
                                        url.searchParams.set('search', '(name = ' + val + ')');
                                        url.searchParams.set('all-dates', '1');
                                        url.searchParams.delete('page');
                                        window.location.href = url.toString();
                                    }
                                }
                            }
                        });
                        $input.on('input', function () {
                            applyFilters($table);
                        });
                        $td.append($input);
                    }
                }
                $filterRow.append($td);
            });

            $thead.append($filterRow);
        });
    });

    function applyFilters($table) {
        var filters = [];
        $table.find('.filter-row .col-filter').each(function () {
            var $el = $(this);
            var colIdx = $el.closest('td').index();
            var val = $el.val().trim();
            var isSelect = $el.is('select');
            if (val) {
                if (val === '__has_budget__') {
                    filters.push({ col: colIdx, text: val, hasBudget: true });
                } else {
                    filters.push({ col: colIdx, text: val.toLowerCase(), exact: isSelect });
                }
            }
        });

        $table.find('tbody tr').each(function () {
            var $row = $(this);
            var show = true;

            for (var i = 0; i < filters.length; i++) {
                var cell = $row[0].cells[filters[i].col];
                var cellText = (cell ? cell.textContent : '').trim();
                if (filters[i].hasBudget) {
                    if (cellText === '-' || cellText === '') {
                        show = false;
                        break;
                    }
                } else if (filters[i].exact) {
                    if (cellText !== filters[i].text && cellText.toLowerCase() !== filters[i].text) {
                        show = false;
                        break;
                    }
                } else {
                    if (cellText.toLowerCase().indexOf(filters[i].text) === -1) {
                        show = false;
                        break;
                    }
                }
            }

            $row.toggle(show);
        });
    }

    function compare(a, b, type) {
        switch (type) {
            case 'number':
            case 'price':
                return toNumber(a) - toNumber(b);
            case 'date-de':
                return parseDateDe(a) - parseDateDe(b);
            default: // text
                return a.localeCompare(b, 'de', { sensitivity: 'base' });
        }
    }

    function toNumber(s) {
        // German format: 1.500,00 EUR → 1500.00
        s = s.replace(/[^\d.,\-]/g, '');
        s = s.replace(/\./g, '');
        s = s.replace(',', '.');
        var n = parseFloat(s);
        return isNaN(n) ? 0 : n;
    }

    function parseDateDe(s) {
        // "16.07.2026" or "16.07.2026, 08:00"
        var m = s.match(/(\d{2})\.(\d{2})\.(\d{4})/);
        if (!m) return 0;
        var d = new Date(parseInt(m[3], 10), parseInt(m[2], 10) - 1, parseInt(m[1], 10));
        var t = s.match(/(\d{2}):(\d{2})/);
        if (t) {
            d.setHours(parseInt(t[1], 10), parseInt(t[2], 10));
        }
        return d.getTime();
    }

})(jQuery);
